// Rate limiting check using in-memory window
// Note: For production, use external rate limiter (Redis, etc.)
// This stub provides structure for rate limiting logic

// n8n webhook puts POST body directly in $json (not $json.body)
const webhookData = $('Webhook').first().json;
const webhookBody = webhookData.body || webhookData; // Handle both formats
const clientIp = webhookData.headers?.['x-forwarded-for'] || 
                 webhookData.headers?.['x-real-ip'] || 
                 'unknown';

// Log rate limit check (actual enforcement at infrastructure level)
console.log(`Rate limit check for IP: ${clientIp}`);
console.log(`Webhook body keys: ${Object.keys(webhookBody).join(', ')}`);

// Pass through with rate limit metadata
return [{
  json: {
    ...webhookBody,
    _rateLimitMeta: {
      clientIp,
      timestamp: new Date().toISOString(),
      // In production, check against Redis/memory store
      allowed: true
    }
  }
}];

// Merge thresholds config and intake-classify agent prompt from fetched data
const allItems = $input.all();
const webhookData = $('Rate Limit Check').first().json;

let thresholdsConfig = {};
let intakeClassifyPrompt = null;

for (const item of allItems) {
  const data = item.json;
  // Thresholds config has runtime/ingestion/publishing sections
  if (data.runtime || data.ingestion || data.publishing || data.rate_limiting) {
    thresholdsConfig = data;
  }
  // Intake classify prompt has content field
  else if (data.content && (data.name === 'intake-classify' || data.content.includes('intake classifier'))) {
    intakeClassifyPrompt = data;
  } else if (data.content) {
    // Fallback: any content is likely the prompt
    intakeClassifyPrompt = data;
  }
}

// Get rate limiting config
const rateLimiting = thresholdsConfig.rate_limiting || {};
const configInfo = {
  requestsPerMinute: rateLimiting.requests_per_minute || 10,
  requestsPerHour: rateLimiting.requests_per_hour || 100,
  globalPerMinute: rateLimiting.global_per_minute || 100
};

console.log(`Loaded thresholds config: runtime.use_stubs=${thresholdsConfig.runtime?.use_stubs}`);
console.log(`Loaded intake-classify prompt: ${intakeClassifyPrompt?.content?.length || 0} chars`);
console.log(`Rate limiting config loaded: ${JSON.stringify(configInfo)}`);

return [{
  json: {
    ...thresholdsConfig,
    _agents: {
      intakeClassify: intakeClassifyPrompt?.content || ''
    },
    _webhookData: webhookData,
    _rateLimitConfig: configInfo
  }
}];

// Validate input with thresholds from config
const merged = $input.first().json;
const rateLimiting = merged._rateLimitConfig || {};
const agents = merged._agents;
const webhookData = merged._webhookData;
const runtimeConfig = merged.runtime || { use_stubs: true };

if (!webhookData?.message || webhookData.message.trim().length < 10) {
  throw new Error('Message required (min 10 chars)');
}

return [{
  json: {
    message: webhookData.message.trim(),
    contact: webhookData.contact || null,
    category: webhookData.category || 'other',
    safetyMode: webhookData.safetyMode || false,
    _rateLimitConfig: rateLimiting,
    _agents: agents,
    _runtime: runtimeConfig
  }
}];

const message = $('Insert Submission').first().json.message;
const validateInput = $('Validate Input').first().json;

// Simple keyword-based classification for testing
const tags = [];
if (message.toLowerCase().includes('messaging') || message.toLowerCase().includes('comms')) tags.push('comms');
if (message.toLowerCase().includes('offline')) tags.push('censorship-resistance');
if (message.toLowerCase().includes('secure') || message.toLowerCase().includes('privacy')) tags.push('privacy');
if (message.toLowerCase().includes('bitcoin') || message.toLowerCase().includes('btc')) tags.push('bitcoin');
if (message.toLowerCase().includes('tool') || message.toLowerCase().includes('build')) tags.push('sovereignty');
if (tags.length === 0) tags.push('general');

// Determine category from content
let category = 'other';
if (message.toLowerCase().includes('tool') || message.toLowerCase().includes('need')) category = 'tool-request';
else if (message.toLowerCase().includes('idea') || message.toLowerCase().includes('what if')) category = 'idea';
else if (message.toLowerCase().includes('report') || message.toLowerCase().includes('observed')) category = 'report';
else if (message.toLowerCase().includes('question') || message.includes('?')) category = 'question';
else if (message.toLowerCase().includes('partner') || message.toLowerCase().includes('collaborate')) category = 'collaboration';

// Determine risk level
let risk_level = 'low';
if (message.toLowerCase().includes('activist') || message.toLowerCase().includes('dissident')) risk_level = 'medium';
if (message.toLowerCase().includes('location') && risk_level === 'medium') risk_level = 'high';

// Determine priority
let priority = 'normal';
if (message.toLowerCase().includes('urgent') || message.toLowerCase().includes('emergency')) priority = 'urgent';
if (message.toLowerCase().includes('fyi') || message.toLowerCase().includes('just sharing')) priority = 'low';

// Check for spam patterns
const is_spam = message.toLowerCase().includes('crypto airdrop') || 
                message.toLowerCase().includes('click here') ||
                (message.match(/https?:\/\//g) || []).length > 5;

// Determine if response is needed
const requires_response = category !== 'other' && !is_spam && 
                          (message.includes('?') || category === 'tool-request' || category === 'collaboration');

// Generate summary
const summary = message.substring(0, 180).replace(/\n/g, ' ').trim() + (message.length > 180 ? '...' : '');

// Suggested assignee
let suggested_assignee = 'triage';
if (category === 'tool-request') suggested_assignee = 'engineering';
else if (category === 'collaboration') suggested_assignee = 'partnerships';
else if (category === 'report') suggested_assignee = 'research';

const result = {
  category,
  tags,
  risk_level,
  priority,
  summary,
  is_spam,
  requires_response,
  suggested_assignee
};

// Match Claude API response format
return [{
  json: {
    content: [{
      type: 'text',
      text: JSON.stringify(result)
    }],
    _submissionId: $('Insert Submission').first().json.id,
    _message: message,
    _agents: validateInput._agents,
    _runtime: validateInput._runtime
  }
}];

