// Process real Claude API response and add pass-through data
const claudeResponse = $input.first().json;
const validateInput = $('Validate Input').first().json;
const submissionData = $('Insert Submission').first().json;

// Return in same format as stub for Parse LLM Response compatibility
return [{
  json: {
    content: claudeResponse.content,
    _submissionId: submissionData.id,
    _message: submissionData.message,
    _agents: validateInput._agents,
    _runtime: validateInput._runtime
  }
}];

// Parse LLM response (handles both stub and real Claude responses)
// Strips markdown code blocks that Claude often wraps JSON in
const input = $input.first().json;
let parsed;

try {
  let text = input.content[0].text;

  // Strip markdown code blocks if present (Claude often wraps JSON in ```json...```)
  text = text.trim();
  if (text.startsWith('```')) {
    // Remove opening fence (```json or ```)
    text = text.replace(/^```(?:json)?\s*\n?/, '');
    // Remove closing fence
    text = text.replace(/\n?```\s*$/, '');
  }

  parsed = JSON.parse(text.trim());
} catch (e) {
  console.log('Parse LLM Response error:', e.message);
  console.log('Raw text:', input.content?.[0]?.text?.substring(0, 200));
  // Fallback classification if parsing fails
  parsed = {
    category: 'other',
    tags: ['general'],
    risk_level: 'low',
    priority: 'normal',
    summary: 'Failed to parse classification: ' + e.message,
    is_spam: false,
    requires_response: false,
    suggested_assignee: 'triage'
  };
}

// Ensure all required fields are present
const result = {
  category: parsed.category || 'other',
  tags: Array.isArray(parsed.tags) ? parsed.tags : ['general'],
  risk_level: parsed.risk_level || 'low',
  priority: parsed.priority || 'normal',
  summary: (parsed.summary || '').substring(0, 200),
  is_spam: Boolean(parsed.is_spam),
  requires_response: Boolean(parsed.requires_response),
  suggested_assignee: parsed.suggested_assignee || 'triage',
  submissionId: input._submissionId,
  message: input._message,
  _runtime: input._runtime
};

return [{ json: result }];

const parsed = $('Parse LLM Response').first().json;

return [{
  json: {
    html_url: `https://github.com/FGUTech/libertas/issues/MOCK-${parsed.submissionId.slice(0, 8)}`,
    number: Math.floor(Math.random() * 1000),
    title: `[Intake] ${parsed.summary.substring(0, 60)}`,
    state: 'open',
    _parsedData: parsed
  }
}];

