// Handle errors from Claude API call
// This provides graceful degradation when API fails

const error = $input.first().json;
const validateInput = $('Validate Input').first().json;
const submissionData = $('Insert Submission').first().json;

console.log('Claude API error:', JSON.stringify(error));

// Create fallback classification
const fallbackClassification = {
  category: 'other',
  tags: ['needs-review'],
  risk_level: 'medium',  // Conservative default
  priority: 'normal',
  summary: 'Auto-classified due to API error - requires manual review',
  is_spam: false,
  requires_response: true,
  suggested_assignee: 'triage'
};

// Return in same format as successful response
return [{
  json: {
    content: [{
      type: 'text',
      text: JSON.stringify(fallbackClassification)
    }],
    _submissionId: submissionData.id,
    _message: submissionData.message,
    _agents: validateInput._agents,
    _runtime: validateInput._runtime,
    _apiError: true
  }
}];

// Handle errors from GitHub API call
// This provides graceful degradation when API fails

const error = $input.first().json;
const parsedData = $('Parse LLM Response').first().json;

console.log('GitHub API error:', JSON.stringify(error));

// Return mock issue URL to allow workflow to continue
return [{
  json: {
    html_url: null,  // No issue created
    number: null,
    title: `[Intake] ${parsedData.summary.substring(0, 60)}`,
    state: 'error',
    _parsedData: parsedData,
    _apiError: true,
    _errorMessage: 'GitHub issue creation failed - will retry later'
  }
}];
